INSERT INTO `characters` (`id`, `name`, `element`, `weapon`, `rarity`, `guide_content`, `image_url`, `mat_1`, `mat_2`, `mat_3_tier1`, `mat_3_tier2`, `mat_3_tier3`, `mat_3_tier4`, `hp_base`, `hp_max`, `atk_base`, `atk_max`, `def_base`, `def_max`) VALUES
(1, 'Sigrika', 'Aero', 'Gauntlets', 5, 'Sigrika in Wuthering Waves is a 5 Stars Aero character who wields a Gauntlets as their weapon type.\r\n\r\nSigrika, a student of Startorch Academy and a Resonator of Royan Runes. Determined to live up to others\' expectations and become a true Solsworn, she devotes herself fully to every challenge.', 'sigrika.jpg', 'Our Choice', 'Arithmetic Shell', 'Fractured Exoswarm Pendant', 'Worn Exoswarm Pendant', 'Chipped Exoswarm Pendant', 'Intact Exoswarm Pendant', 862, 10775, 35, 437, 93, 1136),
(2, 'Luuk Herssen', 'Spectro', 'Gauntlets', 5, 'Luuk Herssen in Wuthering Waves is a 5 Stars Spectro character who wields a Gauntlets as their weapon type.\r\n\r\nThe attending physician of Startorch Academy\'s Resonator Nursing Unit, renowned for his keen intellect and unshakable composure. Rumor has it nobody has ever seen him lose control. He is a keen listener adept at dissecting the shadows in a person\'s heart. From the unhealing wound on his hand, golden blood seeps, a substance he can summon to become a blade of utmost precision.', 'luuk_herssen.jpg', 'Suncoveter\'s Reach', 'Edelschnee', 'Fractured Exoswarm Pendant', 'Worn Exoswarm Pendant', 'Chipped Exoswarm Pendant\r\n', 'Intact Exoswarm Pendant', 824, 10300, 37, 462, 91, 1112),
(3, 'Aemeath', 'Fusion', 'Sword', 5, 'Aemeath in Wuthering Waves is a 5 Stars Fusion character who wields a Sword as their weapon type.\r\nOnce an Exostrider Synchronist of Rabelle College, she is now a digital ghost who sings quietly amongst stars.', 'aemeath.jpg', 'Our Choice', 'Moss Amber', 'LF Exoswarm Core', 'MF Exoswarm Core', 'HF Exoswarm Core', 'FF Exoswarm Core', 882, 11025, 34, 425, 94, 1148),
(4, 'Mornye', 'Fusion', 'Broadblade', 5, 'Mornye in Wuthering Waves is a 5 Stars Fusion character who wields a Broadblade as their weapon type.\r\n\r\nMornye, a Spacetrek Collective Research Institute engineer and a Department of Exostrider Engineering professor at Startorch Academy. Each step on her prosthetic legs carries her toward the stars of her dreams.', 'mornye.jpg', 'Burning Judgment', 'Gemini Spore', 'LF Mech Core', 'MF Mech Core', 'HF Mech Core', 'FF Mech Core', 1230, 15375, 23, 287, 111, 1356),
(5, 'Lynae', 'Spectro', 'Pistols', 5, 'Lynae in Wuthering Waves is a 5 Stars Spectro character who wields a Pistols as their weapon type.\r\n\r\nA Startorch Academy prep student whose head-turning, electric style hides an inner focus as explosive as a coiled spring.', 'lynae.jpg', 'Suncoveter\'s Reach', 'Rimewisp', 'LF Exoswarm Core', 'MF Exoswarm Core', 'HF Exoswarm Core', 'FF Exoswarm Core', 979, 12237, 30, 375, 98, 1197),
(6, 'Buling', 'Electro', 'Rectifier', 4, 'Buling in Wuthering Waves is a 4 Stars Electro character who wields a Rectifier as their weapon type.\r\n\r\nTaoist of Mengzhou, Black Shores Consultant, feng shui master, and veteran forum dweller. Easygoing and well-traveled, Buling will \"bling\" whatever you seek.', 'buling.jpg', 'Blighted Crown of Puppet King', 'Pecok Flower', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 850, 10625, 18, 225, 103, 1258),
(7, 'Chisa', 'Havoc', 'Broadblade', 5, 'Chisa in Wuthering Waves is a 5 Stars Havoc character who wields a Broadblade as their weapon type.\r\n\r\n\"Just an ordinary student.\" Calmly, she introduces herself, a faint iridescent shimmer flickering in her eyes. Again, the structures of the world reveal themselves in her vision. Narrowing her eyes, she singles out the very thread that tugs at life itself.', 'chisa.jpg', 'Abyssal Husk', 'Summer Flower', 'LF Polygon Core', 'MF Polygon Core', 'HF Polygon Core', 'FF Polygon Core', 862, 10775, 35, 437, 93, 1136),
(8, 'Qiuyuan', 'Aero', 'Sword', 5, 'Qiuyuan in Wuthering Waves is a 5 Stars Aero character who wields a Sword as their weapon type.\r\n\r\nFormer senior agent of Mingting\'s Internal Security Agency. Though enmity filled his younger days, loyalty defined his later years. However, scapegoated for a murder, he is now but a blind swordsman wandering the world alone.', 'qiuyuan.jpg', 'Truth in Lies\r\n', 'Wintry Bell', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 979, 12237, 30, 375, 98, 1197),
(9, 'Galbrena', 'Fusion', 'Pistols', 5, 'Galbrena in Wuthering Waves is a 5 Stars Fusion character who wields a Pistols as their weapon type.\r\n\r\nCold and decisive, she is the \"Discord Slayer\" who hunts across Solaris and the same \"Fiend of Ever-burning Flame\" spoken of in whispers. Now, she serves as a Black Shores Consultant, active across the world.', 'galbrena.jpg', 'Blighted Crown of Puppet King', 'Stone Rose', 'LF Tidal Residuum', 'MF Tidal Residuum', 'HF Tidal Residuum', 'FF Tidal Residuum', 824, 10300, 37, 462, 91, 1112),
(10, 'Iuno', 'Aero', 'Gauntlets', 5, 'Iuno in Wuthering Waves is a 5 Stars Aero character who wields a Gauntlets as their weapon type.\r\n\r\nShe is favored by fate under one name, and swept away by it in another. Yet never once has she been defeated, nor has she ever yielded. Now, witness the defiant Priestess. Witness what keeps her striding forward, never to look back. Witness how she walks the intricate web of destiny and becomes the only answer.', 'iuno.jpg', 'Abyssal Husk', 'Sliverglow Bloom', 'LF Polygon Core', 'MF Polygon Core', 'HF Polygon Core', 'FF Polygon Core', 842, 10525, 36, 450, 92, 1124),
(11, 'Augusta', 'Electro', 'Broadblade', 5, 'Augusta in Wuthering Waves is a 5 Stars Electro character who wields a Broadblade as their weapon type.\r\n\r\nEphor of Septimont. The undying sun eternally ablaze, and a banner under which defeat does not exist. She comes. She sees. She conquers. With blade held high, she awaits the next challenger or the fate that claims it cannot be defied.', 'augusta.jpg', 'Blighted Crown of Puppet King', 'Luminous Calendula', 'LF Tidal Residuum', 'MF Tidal Residuum', 'HF Tidal Residuum', 'FF Tidal Residuum', 824, 10300, 37, 462, 91, 1112),
(12, 'Phrolova', 'Havoc', 'Rectifier', 5, 'Phrolova in Wuthering Waves is a 5 Stars Havoc character who wields a Rectifier as their weapon type.\r\n\r\nPhrolova, a Fractsidus Overseer walking the fine line between life and death, an uncanny, deadly conductor. A silent wave of her baton is enough to attune the very frequencies of being and conduct the symphonies of \"souls.\" The music of hers can sculpt a better world or, just as easily, summon a legion to wreak havoc.', 'phrolova.jpg', 'Truth in Lies', 'Afterlife', 'LF Polygon Core', 'MF Polygon Core', 'HF Polygon Core', 'FF Polygon Core', 862, 10775, 35, 437, 93, 1136),
(13, 'Lupa', 'Fusion', 'Broadblade', 5, 'Lupa in Wuthering Waves is a 5 Stars Fusion character who wields a Broadblade as their weapon type.\r\n\r\nA Gladiator of Septimont, a radiant star of the arena. Fiery and straightforward, Lupa lives like a wild lone wolf. As long as she can savor the adrenaline rush of battle, she doesn\'t mind if that same fire ends up consuming her whole.', 'lupa.jpg', 'Unfading Glory', 'Bloodleaf Viburnum', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 953, 11912, 31, 387, 97, 1185),
(14, 'Cartethyia', 'Aero', 'Sword', 5, 'Cartethyia in Wuthering Waves is a 5 Stars Aero character who wields a Sword as their weapon type.\r\n\r\nCartethyia, the wandering knight who travels across Rinascita. Formerly known as the Blessed Maiden, the vessel of Divinity, and the Queen of Gale and Tide, she went by the name Fleurdelys. Now, she is simply a free and unfettered wandering knight.\r\n\r\n', 'cartethyia.jpg', 'Unfading Glory', 'Bamboo Iris', 'LF Tidal Residuum', 'MF Tidal Residuum', 'HF Tidal Residuum', 'FF Tidal Residuum', 1184, 14800, 25, 312, 50, 611),
(15, 'Ciaccona', 'Aero', 'Pistols', 5, 'Ciaccona in Wuthering Waves is a 5 Stars Aero character who wields a Pistols as their weapon type.\r\n\r\nA wandering bard from Rinascita, Ciaccona. She sings not only for the Divinity, but also for the common folk. She records stories along her journeys, turning them into songs that evoke laughter, emotion, and tears in both the storytellers and the audience.', 'ciaccona.jpg', 'Blazing Bone', 'Golden Fleece', 'LF Tidal Residuum', 'MF Tidal Residuum', 'HF Tidal Residuum', 'FF Tidal Residuum', 979, 12237, 30, 375, 98, 1197),
(16, 'Zani', 'Spectro', 'Gauntlets', 5, 'Zani in Wuthering Waves is a 5 Stars Spectro character who wields a Gauntlets as their weapon type.\r\n\r\nA member of Averardo Vault\'s security team and holder of \"Best Employee\" for longer than she cares to count. She has made plenty of plans for her free time, but for now, her biggest mission is simple: clocking out on time.', 'zani.jpg', 'Platinum Core', 'Sword Acorus', 'LF Polygon Core', 'MF Polygon Core', 'HF Polygon Core', 'FF Polygon Core', 862, 10775, 35, 437, 93, 1136),
(17, 'Cantarella', 'Havoc', 'Rectifier', 5, 'Cantarella in Wuthering Waves is a 5 Stars Havoc character who wields a Rectifier as their weapon type.\r\n\r\nThe current head of Fisalia, Cantarella, the Bane. A mysterious noblewoman, her beauty as captivating as it is perilous. She resides in a crown-like castle perched atop the mountain, where illusory dreams flow like streams, meticulously spun by her own hands.', 'cantarella.jpg', 'Cleansing Conch\r\n', 'Seaside Cendrelis', 'LF Polygon Core', 'MF Polygon Core', 'HF Polygon Core', 'FF Polygon Core', 928, 11600, 32, 400, 90, 1099),
(18, 'Brant', 'Fusion', 'Sword', 5, 'Brant in Wuthering Waves is a 5 Stars Fusion character who wields a Sword as their weapon type.\r\n\r\nBrant, the captain of Rinascita\'s Troupe of Fools, is a free spirit and romantic. Unpredictable and full of life, he is the beating heart of the troupe. On stage, he slips into countless roles, donning new masks to breathe life into every story. Yet beyond the spotlight, he is unwaveringly genuine, offering nothing but true sincerity to those around him.\r\n\r\n', 'brant.jpg', 'Blazing Bone', 'Golden Fleece', 'LF Tidal Residuum', 'MF Tidal Residuum', 'HF Tidal Residuum', 'FF Tidal Residuum', 934, 11675, 30, 375, 107, 1307),
(19, 'Phoebe', 'Spectro', 'Rectifier', 5, 'Phoebe in Wuthering Waves is a 5 Stars Spectro character who wields a Rectifier as their weapon type.\r\n\r\nPhoebe, Acolyte of the Order of the Deep, is a young woman of quiet devotion. With a kind heart, she fulfills her duties with unwavering diligence. Her prayers, like the light she carries, offer comfort and peace to all.', 'phoebe.jpg', 'Cleansing Conch', 'Firecracker Jewelweed', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 866, 10825, 33, 412, 103, 1258),
(20, 'Roccia', 'Havoc', 'Gauntlets', 5, 'Roccia in Wuthering Waves is a 5 Stars Havoc character who wields a Gauntlets as their weapon type.\r\n\r\nAssistant, prop master, and improv comedian, Roccia is always there to make sure the Troupe of Fools is at the ready. The Magic Box she carries appears to hold the world, or perhaps she had recreated a world inside the box.', 'roccia.jpg', 'Cleansing Conch', 'Firecracker Jewelweed', 'LF Tidal Residuum', 'MF Tidal Residuum', 'HF Tidal Residuum', 'FF Tidal Residuum', 980, 12250, 30, 375, 98, 1197),
(21, 'Carlotta', 'Glacio', 'Pistols', 5, 'Carlotta in Wuthering Waves is a 5 Stars Glacio character who wields a Pistols as their weapon type.\r\n\r\nThe second daughter of Montelli and an art investor unbound by convention, Carlotta moves seamlessly through social circles and business transactions while quietly handling the family\'s unspeakable \"troubles\" in secret. The blooming of a \"gem,\" the taking of a life—In her own name, she reshapes reality, giving it a new dimension.', 'carlotta.jpg', 'Platinum Core', 'Sword Acorus', 'LF Polygon Core', 'MF Polygon Core', 'HF Polygon Core', 'FF Polygon Core', 996, 12450, 37, 462, 98, 1197),
(22, 'Lumi', 'Electro', 'Broadblade', 4, 'Lumi in Wuthering Waves is a 4 Stars Electro character who wields a Broadblade as their weapon type.\r\n\r\nNavigator at Lollo Logistics and leader of a transport squad. Born in a mountain village in Yuezhou, Lumi\'s sincere and caring nature brings warmth to everyone around her.', 'lumi.jpg', 'Thundering Tacet Core', 'Terraspawn Fungus', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 680, 8500, 27, 337, 72, 879),
(23, 'Camellya', 'Havoc', 'Sword', 5, 'Camellya in Wuthering Waves is a 5 Stars Havoc character who wields a Sword as their weapon type.\r\n\r\nA Bloom Bearer of the Black Shores, Camellya is free-spirited and dangerously charming. She roams Solaris in search of talent, immersing herself in the present and relishing its pleasures, all while remaining true to herself, unburdened by thoughts of the past or future.', 'camellya.jpg', 'Topological Confinement', 'Nova', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 826, 10325, 36, 450, 95, 1161),
(24, 'Youhu', 'Glacio', 'Gauntlets', 4, 'Youhu in Wuthering Waves is a 4 Stars Glacio character who wields a Gauntlets as their weapon type.\r\n\r\nA voluble and whimsical antique appraiser. Known for creating limericks on the spot, she presents her appraisals with flair and precision. She sets up a stall on the street, ensuring antiques find their way to those who truly cherish them.', 'youhu.jpg', 'Topological Confinement', 'Violet Coral', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 798, 9975, 21, 262, 86, 1051),
(25, 'Shorekeeper', 'Spectro', 'Rectifier', 5, 'Shorekeeper in Wuthering Waves is a 5 Stars Spectro character who wields a Rectifier as their weapon type.\r\n\r\nThe Shorekeeper, guardian of the Black Shores—this title alone once defined her. But desires, bonds, and emotions… She only began to understand these things after meeting you.', 'shorekeeper.jpg', 'Topological Confinement', 'Nova', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 1337, 16712, 23, 287, 90, 1099),
(26, 'Xiangli Yao', 'Electro', 'Gauntlets', 5, 'Xiangli Yao in Wuthering Waves is a 5 Stars Electro character who wields a Gauntlets as their weapon type.\r\n\r\nPrincipal Investigator at Jinzhou Huaxu Academy, and the Academy\'s youngest multi-disciplinary scientist. A gentle soul with a sharp mind, whose relentless passion for Automata Mechanics always translates into constructive findings and insights.', 'xiangliyao.jpg', 'Hidden Thunder Tacet Core', 'Violet Coral', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 850, 10625, 34, 425, 100, 1222),
(27, 'Zhezhi', 'Glacio', 'Rectifier', 5, 'Zhezhi in Wuthering Waves is a 5 Stars Glacio character who wields a Rectifier as their weapon type.\r\n\r\nAn artist for hire trying to make a living. Reserved and timid, she is not good with words but speaks volumes through her art, where her creations come to life with impossible authenticity.', 'zhezhi.jpg', 'Sound-Keeping Tacet Core', 'Lanternberry', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 980, 12250, 30, 375, 98, 1197),
(28, 'Changli', 'Fusion', 'Sword', 5, 'Changli in Wuthering Waves is a 5 Stars Fusion character who wields a Sword as their weapon type.\r\n\r\nChangli is a counselor serving the Jinzhou Magistrate, and former Secretary-General in the capital. Shrouded in flames, she\'s fated to burn brightly until her final embers. With her fiery determination and strategic mindset, she rises to power, always thinking ahead to reach her ultimate goal.', 'changli.jpg', 'Rage Tacet Core', 'Pavo Plum', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 831, 10387, 37, 462, 90, 1099),
(29, 'Jinhsi', 'Spectro', 'Broadblade', 5, 'Jinhsi in Wuthering Waves is a 5 Stars Spectro character who wields a Broadblade as their weapon type.\r\n\r\nJinhsi, Magistrate of Jinzhou, gently brightens the hopes of her people, like rays of winter sunlight. As the revered Sentinel\'s Appointed Resonator, she displays humility and wholeheartedly commits herself to guiding her people towards a brilliant future.', 'jinhsi.jpg', 'Elegy Tacet Core', 'Loong\'s Pearl', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 866, 10825, 33, 412, 103, 1258),
(30, 'Yinlin', 'Electro', 'Rectifier', 5, 'Yinlin in Wuthering Waves is a 5 Stars Electro character who wields a Rectifier as their weapon type.\r\n\r\nYinlin is a skilled Patroller and powerful Natural Resonator. After being suspended from her duties at the Public Security Bureau, she must now pursue hidden evils in secrecy.', 'yinlin.jpg', 'Group Abomination Tacet Core', 'Coriolus', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 880, 11000, 32, 400, 105, 1283),
(31, 'Jiyan', 'Aero', 'Broadblade', 5, 'Jiyan in Wuthering Waves is a 5 Stars Aero character who wields a Broadblade as their weapon type.\r\n\r\nJiyan, leader of the Midnight Rangers, acts with swift and resolute righteousness. He possesses the formidable ability to conjure a powerful Qingloong from the winds, making him invincible on the battlefield.', 'jiyan.jpg', 'Roaring Rock Fist', 'Pecok Flower', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 839, 10487, 35, 437, 97, 1185),
(32, 'Rover (Aero)', 'Aero', 'Sword', 5, 'Rover (Aero) in Wuthering Waves is a 5 Stars Aero character who wields a Sword as their weapon type.\r\n\r\nA mysterious Resonator with the power to absorb all sounds. Currently journeying to find their lost memories.', 'rover_aero.jpg', 'Mysterious Code', 'Pecok Flower', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 862, 10775, 35, 437, 93, 1136),
(33, 'Rover (Havoc)', 'Havoc', 'Sword', 5, 'Rover (Havoc) in Wuthering Waves is a 5 Stars Havoc character who wields a Sword as their weapon type.\r\n\r\nA mysterious Resonator with the power to absorb all sounds. Currently journeying to find their lost memories.', 'rover_havoc.jpg', 'Mysterious Code', 'Pecok Flower', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 862, 10775, 35, 437, 93, 1136),
(34, 'Rover (Spectro)', 'Spectro', 'Sword', 5, 'Rover (Spectro) in Wuthering Waves is a 5 Stars Spectro character who wields a Sword as their weapon type.\r\n\r\nA mysterious Resonator with the power to absorb all sounds. Currently journeying to find their lost memories.', 'rover_spectro.jpg', 'Mysterious Code', 'Pecok Flower', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 862, 10775, 35, 437, 93, 1136),
(35, 'Jianxin', 'Aero', 'Gauntlets', 5, 'Jianxin in Wuthering Waves is a 5 Stars Aero character who wields a Gauntlets as their weapon type.\r\n\r\nJianxin, a Taoist monk and successor of Fengyiquan, has dedicated her life to mastering the ultimate martial art. With the power to harness and transform environmental Chi, she can create protective barriers that purify both body and mind.', 'jianxin.jpg', 'Roaring Rock Fist', 'Lanternberry', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 1129, 14112, 27, 337, 92, 1124),
(36, 'Calcharo', 'Electro', 'Broadblade', 5, 'Calcharo in Wuthering Waves is a 5 Stars Electro character who wields a Broadblade as their weapon type.\r\n\r\nLeader of the \"Ghost Hounds,\" an international mercenary group. Ruthless, vengeful, unforgiving. His Forte allows him to summon a special Tacet Discord to assist his assault on the targets. A potential client must be mindful of the price to pay before making him an offer.', 'calcharo.jpg', 'Thundering Tacet Core', 'Iris', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 840, 10500, 35, 437, 97, 1185),
(37, 'Encore', 'Fusion', 'Rectifier', 5, 'Encore in Wuthering Waves is a 5 Stars Fusion character who wields a Rectifier as their weapon type.\r\n\r\nA girl accompanied by one black and one white Wooly. Encore, consultant from the Black Shores, dreams of creating happy stories with candies, fairy tales, and her imagination.', 'encore.jpg', 'Rage Tacet Core', 'Pecok Flower', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 841, 10512, 34, 425, 102, 1246),
(38, 'Lingyang', 'Glacio', 'Gauntlets', 5, 'Lingyang in Wuthering Waves is a 5 Stars Glacio character who wields a Gauntlets as their weapon type.\r\n\r\nAn enthusiastic, brave member of the Liondance Troupe in Jinzhou, Lingyang is a sincere, compassionate visitor of the human community with incredible physical abilities, whose interest in humans easily shows. With his unique style, he embodies the spirit of Liondance.', 'lingyang.jpg', 'Sound-Keeping Tacet Core', 'Coriolus', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 831, 10387, 35, 437, 99, 1209),
(39, 'Verina', 'Spectro', 'Rectifier', 5, 'Verina in Wuthering Waves is a 5 Stars Spectro character who wields a Rectifier as their weapon type.\r\n\r\nWith an extensive knowledge of botany, Verina is always solicitous, always smiling, and always wishing for every flower to be blessed with the miracle of life.', 'verina.jpg', 'Elegy Tacet Core', 'Belle Poppy', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 1139, 14237, 27, 337, 90, 1099),
(40, 'Aalto', 'Aero', 'Pistols', 4, 'Aalto in Wuthering Waves is a 4 Stars Aero character who wields a Pistols as their weapon type.\r\n\r\nAalto is an enigmatic Information Broker, known for his elusive nature and welcoming smile. Underneath the facade, he is closely affiliated with the Black Shores. Rumor has it he\'ll provide any information at the right price.', 'aalto.jpg', 'Roaring Rock Fist', 'Wintry Bell', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 788, 9850, 21, 262, 88, 1075),
(41, 'Yangyang', 'Aero', 'Sword', 4, 'Yangyang in Wuthering Waves is a 4 Stars Aero character who wields a Sword as their weapon type.\r\n\r\nYangyang is an Outrider of the Midnight Rangers. Once sheltered, now a fighter. She soars with the wind to protect others, like a skylark in flight.', 'yangyang.jpg', 'Roaring Rock Fist', 'Wintry Bell', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 816, 10200, 20, 250, 90, 1099),
(42, 'Yuanwu', 'Electro', 'Gauntlets', 4, 'Yuanwu in Wuthering Waves is a 4 Stars Electro character who wields a Gauntlets as their weapon type.\r\n\r\nYuanwu owns a boxing gym where he teaches Leihuangquan and health management. He is well-respected in the community for his cordial demeanor and pleasant temperament.', 'yuanwu.jpg', 'Hidden Thunder Tacet Core', 'Terraspawn Fungus', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 682, 8525, 18, 225, 134, 1637),
(43, 'Chixia', 'Fusion', 'Pistols', 4, 'Chixia in Wuthering Waves is a 4 Stars Fusion character who wields a Pistols as their weapon type.\r\n\r\nChixia is a spirited young Jinzhou Patroller who lights up the streets of Jinzhou. She\'s always ready to be the hero someone needs. She fuses such passion into the bullets that blast out of her fingertips.', 'chixia.jpg', 'Rage Tacet Core', 'Belle Poppy', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 727, 9087, 24, 300, 78, 953),
(44, 'Mortefi', 'Fusion', 'Pistols', 4, 'Mortefi in Wuthering Waves is a 4 Stars Fusion character who wields a Pistols as their weapon type.\r\n\r\nMortefi, a skilled expert in Applied Tacetite Study and a member of the Academy’s Department of Safety, possesses the unique ability to transform his accumulated frustration into fiery flames. From a burning wrath that consumes all, the red dragon shall descend.', 'mortefi.jpg', 'Rage Tacet Core', 'Coriolus', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 802, 10025, 20, 250, 93, 1136),
(45, 'Sanhua', 'Glacio', 'Sword', 4, 'Sanhua in Wuthering Waves is a 4 Stars Glacio character who wields a Sword as their weapon type.\r\n\r\nThe bodyguard of Jinzhou\'s Magistrate, known for having an icy personality. Once regarded as the Asura of Calamity, Sanhua is now a taciturn guardian. She has learned to maintain inner calmness amidst the chaotic frequencies, and the things that once frightened her now fuel her determination.', 'sanhua.jpg', 'Sound-Keeping Tacet Core', 'Wintry Bell', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 805, 10062, 22, 275, 77, 941),
(46, 'Baizhi', 'Glacio', 'Rectifier', 4, 'Baizhi in Wuthering Waves is a 4 Stars Glacio character who wields a Rectifier as their weapon type.\r\n\r\nBaizhi is a researcher in Remnant Ecoacoustics. Baizhi\'s once unfulfilled wish has now manifested as her loyal companion. The Remnant Creature You\'tan is her source of healing powers, and a lifelong research focus.', 'baizhi.jpg', 'Sound-Keeping Tacet Core', 'Lanternberry', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 1025, 12812, 17, 212, 82, 1002),
(47, 'Danjin', 'Havoc', 'Sword', 4, 'Danjin in Wuthering Waves is a 4 Stars Havoc character who wields a Sword as their weapon type.\r\n\r\nWith a vengeful blade of condensed blood in hand, Ranger Danjin hunts down thieves and bandits for retribution. She journeys to distant lands in pursuit of justice.', 'danjin.jpg', 'Strife Tacet Core', 'Belle Poppy', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 755, 9437, 21, 262, 94, 1148),
(48, 'Taoqi', 'Havoc', 'Broadblade', 4, 'Taoqi in Wuthering Waves is a 4 Stars Havoc character who wields a Broadblade as their weapon type.\r\n\r\nTaoqi is the director of border defense at the Ministry of Development. Despite her seemingly laid-back demeanor, she consistently proves to be a dependable and supportive individual, always lending her hand to those in need. Taoqi is not only a reliable colleague, but also a trustworthy friend that people can confide in.', 'taoqi.jpg', 'Gold-Dissolving Feather', 'Iris', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 716, 8950, 18, 225, 128, 1564);
