INSERT INTO `weapons` (`id`, `name`, `type`, `rarity`, `main_stat`, `image_url`, `description`, `story`, `atk_base`, `atk_max`, `stat_base`, `stat_max`, `mat_1_t1`, `mat_1_t2`, `mat_1_t3`, `mat_1_t4`, `mat_2_t1`, `mat_2_t2`, `mat_2_t3`, `mat_2_t4`, `skill_name`) VALUES
(191, 'Lustrous Razor', 'Broadblade', 5, 'ATK%', 'wp_lustrous_razor.png', 'Increases Energy Regen by [12.8, 3.2]%. When Resonance Skill is cast, Resonance Liberation DMG Bonus is increased by [7, 1.75]%, stacking up to 3 times. This effect lasts for 12s.', 'A broadblade incorporating advanced technologies. It responds to the wielder’s frequency and unleashes a destructive energy blade that can tear through the night.', 47, 587, '8.10%', '36.40%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Stormy Resolution'),
(192, 'Emerald of Genesis', 'Sword', 5, 'Crit Rate%', 'wp_emerald_of_genesis.png', 'Increases Energy Regen by [12.8, 3.2]%. When Resonance Skill is cast, increases ATK by [6, 1.5]%, stacking up to 2 time(s). This effect lasts for 10s.', 'Pay heed: the frigid blade reveals an icy current, amalgamating into a whirlpool of thoughts. Use this powerful sequence to effortlessly crush your enemies with the Sword.', 47, 587, '5.40%', '24.30%', 'Inert Metallic Drip', 'Reactive Metallic Drip\r\n', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Stormy Resolution'),
(193, 'Static Mist', 'Pistols', 5, 'Crit Rate%', 'wp_static_mist.png', 'Increases Energy Regen by [12.8, 3.2]%. Incoming Resonator\'s ATK is increased by [10, 2.5]% for 14s, stackable for up to 1 times after the wielder casts Outro Skill.', 'Grip the sleek frame and feel its cool surface as you aim down the sight. With a pull of the trigger, unleash a thick smoke barrage onto the battlefield with these powerful Pistols in your hands.', 47, 587, '5.40%', '24.30%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Stormy Resolution'),
(194, 'Abyss Surges', 'Gauntlets', 5, 'ATK%', 'wp_abyss_surges.png', 'Increases Energy Regen by [12.8, 3.2]%. When hitting a target with Resonance Skill, increases Basic Attack DMG Bonus by [10, 2.5]%, lasting for 8s. When hitting a target with Basic Attacks, increases Resonance Skill DMG Bonus by [10, 2.5]%, lasting for 8s.', 'The Gauntlets pulsate with an uncontrollable force, emanating unspeakable anger from the depths of the unknown lake. As you don them, unleash your fury on helpless enemies. Feel its power surge through you.', 47, 587, '8.10%', '36.45%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Stormy Resolution'),
(195, 'Cosmic Ripples', 'Rectifier', 5, 'ATK%', 'wp_cosmic_ripples.png', 'Increases Energy Regen by [12.8, 3.2]%. When dealing Basic Attack DMG, increases Basic Attack DMG Bonus by [3.2, 0.8]%, stacking up to 5 time(s). This effect lasts for 8s and can be triggered 1 time(s) every 0.5s.', 'Take hold of the frozen Rectifier, a powerful tool imbued with the energy of the celestial lake. Let it lead you to ultimate knowledge and vanquish all obstacles in your path.', 40, 500, '12.00%', '54.00%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Stormy Resolution'),
(196, 'Verdant Summit', 'Broadblade', 5, 'Crit DMG%', 'wp_verdant_summit.png', 'Increases Attribute DMG Bonus by [12, 3]%. Every time Intro Skill or Resonance Liberation is cast, increases Heavy Attack DMG Bonus by [24, 6]%, stacking up to 2 time(s). This effect lasts for 14s.', 'The ancient mountain stands tall, its peak reaching towards the sky. A river flows for thousands of years, forming the blade of a powerful weapon. As it is unsheathed, a powerful dragon\'s roar echoes through the heavens and earth, causing the sea to churn. This awe-inspiring weapon strikes fear in all who witness its might.', 47, 587, '10.80%', '48.60%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core\r\n', 'HF Whisperin Core', 'FF Whisperin Core', 'Swordsworn'),
(197, 'Stringmaster', 'Rectifier', 5, 'Crit Rate%', 'wp_stringmaster.png', 'Grants [12, 3]% Attribute DMG Bonus. When dealing Resonance Skill DMG, increases ATK by [12, 3]%, stacking up to 2 times. This effect lasts for 5s. When the wielder is not on the field, increases their ATK by an additional [12, 3]%.', 'The puppet\'s palm unfurls, releasing deadly strings with a menacing hum. The air crackles, immobilizing foes and leaving unhealable scars from rapid electric bolts.', 40, 500, '8.00%', '36.00%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Electric Amplification'),
(198, 'Ages of Harvest', 'Broadblade', 5, 'Crit Rate%', 'wp_ages_of_harvest.png', 'Grants [12, 3]% Attribute DMG Bonus. Casting Intro Skill gives the equipper Ageless Marking, which grants [24, 6]% Resonance Skill DMG Bonus for 12s. Casting Resonance Skill gives the equipper Ethereal Endowment, which grants [24, 6]% Resonance Skill DMG Bonus for 12s.', 'Each swing of the blade reveals the flow of time and the change of the stars. The sword embodies all things, uniting them into one. Its gentle aura seems capable of dissolving the indestructible, whether it\'s millennia-old ice or the stagnation of time.', 47, 587, '5.40%', '24.30%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core\r\n', 'FF Whisperin Core', 'Divine Blessing'),
(199, 'Blazing Brilliance', 'Sword', 5, 'Crit DMG%', 'wp_blazing_brilliance.png', 'ATK increased by [12, 3]%. The wielder gains 1 stack of Searing Feather upon dealing damage, which can be triggered once every 0.5s, and gains 5 stacks of the same effect upon casting Resonance Skill. Each stack of Searing Feather gives [4, 1]% additional Resonance Skill DMG Bonus for up to 14 stacks. After reaching the max stacks, all stacks will be removed in 12s.\r\n\r\n', 'Forged from the very essence and feathers of a legendary bird, this weapon blazes with an intensity that bathes the world in its luminous glow. With each fiery surge, it consumes all in its path, leaving nothing but ashes in its wake.', 47, 587, '10.80%', '48.60%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Crimson Phoenix'),
(200, 'Rime-Draped Sprouts', 'Rectifier', 5, 'Crit DMG%', 'wp_rime_draped_sprouts.png', 'Increase ATK by [12, 3]%. While the wielder is on the field, using Resonance Skill grants [12, 3]% Basic Attack DMG Bonus, stacking up to 3 times for 6s. At 3 stacks or above, casting Outro Skill consumes all stacks of this effect and grants the wielder [52, 13]% Basic Attack DMG Bonus for 27s, effective when the wielder is off the field.', 'An artist\'s seal adorned with rimed sprouts. It is stamped on numerous paintings that capture mountains and ravines in expressive, mesmerizing strokes. The tender sprouts symbolize the perpetual blossoming of artistic marvels.', 40, 500, '16.00%', '72.00%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring\r\n', 'Panorama'),
(201, 'Verity\'s Handle', ' Gauntlets', 5, 'Crit Rate%', 'wp_verity_s_handle.png', 'Gain [12, 3]% Attribute DMG Bonus. When using Resonance Liberation, the wielder gains [48, 12]% Resonance Liberation DMG Bonus for 8s. This effect can be extended by 5s each time Resonance Skills are cast, up to 3 times.', 'Crafted with the lost art from the Court of Savantae, these gauntlets are solid and unbreakable, despite their lightweight materials. They are no tools of violence or aggression, but instruments for unraveling puzzles and pursuing the truth.', 47, 587, '5.40%', '24.30%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Ad Veritatem'),
(202, 'Stellar Symphony', 'Rectifier', 5, 'Energy Regen%', 'wp_stellar_symphony.png', 'Increase HP by [12, 3]%. Restore [8, 2] Concerto Energy when casting Resonance Liberation. This effect can be triggered 1 time(s) every 20s. When casting Resonance Skill that heals, increase nearby party members\' ATK by [14, 3.5]% for 30s. Effects of the same name cannot be stacked.', 'A rectifier bearing an energy core that simulates the lifecycle of stars—an infinite loop that originates from a singularity and ends in explosive demise. The celestial debris collides in thunderous rumbles, heralding the birth of a new star.', 27, 412, '8.0%', '77.04%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Astral Evolvement'),
(203, 'Red Spring', 'Sword', 5, 'Crit Rate%', 'wp_red_spring.png', 'Increase ATK by [12, 3]%. When dealing Basic Attack DMG, the wielder gains [10, 2.5]% Basic Attack DMG Bonus for 14s. This effect can be triggered once per second, stacking up to 3 times. When the wielder\'s Concerto Energy is consumed, gain [40, 10]% Basic DMG Bonus for 10. This effect can be triggered once per second and ends when the wielder is switched off the field.', 'A camellia bud silently unfurls. As promised, she holds this infinite world in bloom in her palms, where fine crimson vines twine around her fingertips. The dull ache, like sand scratching against the heart, is proof of your fateful encounter.', 47, 587, '5.40%', '24.30%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Beyond the Cycle'),
(204, 'Tragicomedy', ' Gauntlets', 5, 'Crit Rate%', 'wp_tragicomedy.png', 'Increases ATK by [12, 3]%. Every time Basic Attack or Intro Skill is cast, Heavy Attack DMG Bonus increases by [48, 12]% for 3s.', 'The joys and sorrows of life dance in an endless circle; Pain and tears shift in an instant into a carnival.', 47, 587, '5.40%', '24.30%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Fool\'s Warble'),
(205, 'The Last Dance', 'Pistols', 5, 'Crit DMG%', 'wp_the_last_dance.png', 'Increases ATK by [12, 3]%. Every time Intro Skill or Resonance Liberation is cast, Resonance Skill DMG Bonus increases by [48, 12]% for 5s.', 'The radiant crystals, ever shattering and reshaping, beckon you into a treacherous dance, a gamble where life is the wager. Cortado, cortado... relentlessly draw each other in until all we can hear are our quivers. When the crimson finale arrives, remember, death comes for all.\r\n\r\n', 40, 500, '16.00%', '72.00%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Silent Eulogy'),
(206, 'Unflickering Valor', 'Sword', 5, 'Energy Regen%', 'wp_unflickering_valor.png', 'Increase Crit. Rate by [8, 2]%. Casting Resonance Liberation gives [24, 6]% Basic Attack DMG Bonus for 10s. Dealing Basic Attack DMG gives [24, 6]% Basic Attack DMG Bonus for 4s.', 'Blistering winds and crashing waves, the sea devours all. Only a lonely boat lamp stands alight! Onwards! Towards the edge of the world you shall sail!', 33, 412, '17.12%', '77.04%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Laughter Prevails'),
(207, 'Luminous Hymn', 'Rectifier', 5, 'Crit Rate%', 'wp_luminous_hymn.png', 'Increase ATK by [12, 3]%. Dealing DMG to targets with Spectro Frazzle grants the wielder [14, 3.5]% Basic Attack DMG Bonus and [14, 3.5]% Heavy Attack DMG Bonus, stacking up to 3 for 6s. Casting Outro Skill Amplifies the Spectro Frazzle DMG on targets around the active Resonator by [30, 7.5]% for 30s. Effects of the same name cannot be stacked.', '\"The Sentinel\'s grace, how sweet thou art. Our home was lost, but found at last. With twigs between my beaks, I brave the waves. Bound by love, we\'re crowned with holy light.\"', 40, 500, '8.00%', '36.00%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Homebuilder\'s Anthem'),
(208, 'Whispers of Sirens', ' Rectifier', 5, 'Crit DMG%', 'wp_whispers_of_sirens.png', 'Increases ATK by [12, 3]%. Casting Echo Skill within 10s after casting Intro Skill or Basic Attacks grants 1 of Gentle Dream. Echoes with the same name can only trigger this effect once, stacking up to 2 times, lasting for 10s. When reaching 2 stacks, casting Echo Skill no longer resets the duration of this effect. This effect activates up to once per 10s. Switching to another Resonator ends this effect early. With 1 : Grants [40, 10]% Basic Attack DMG Bonus. With 2 : Ignores [12, 3]% of the target\'s Havoc RES.', 'From the sea, some see stars, some catch the moon, and some hear countless whispers and murmurs. Those murmurs seep into her venom, flowing through every winding river. In the end, the murmurs envelope, like the bell of a jellyfish, like the sea.', 40, 500, '16.00%', '72.00%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring\r\n', 'Tailored Ring', 'From the Deep'),
(209, 'Bloodpact\'s Pledge', 'Sword', 5, ' Energy Regen%', 'wp_bloodpact_s_pledge.png', 'Providing Healing increases Resonance Skill DMG by [10, 4]% for 6s. When Rover: Aero casts Resonance Skill Unbound Flow, Aero DMG dealt by nearby Resonators on the field is Amplified by [10, 4]% for 30s.', 'This weapon is a testament to the unbreakable blood pact: One shall never betray, never surrender, and fight until the last drop of blood is shed.', 47, 587, '8.64%', '38.88%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Harmonious Vibrancy'),
(210, 'Blazing Justice', ' Gauntlets', 5, 'Crit DMG%', 'wp_blazing_justice.png', 'Increases ATK by [12, 3]%. Casting Basic Attack grants the following effects: Dealing damage ignores [8, 2]% of the target\'s DEF and Amplifies Spectro Frazzle DMG dealt by [50, 12.5]% for 6s. Retriggering the effect resets its duration.', 'It heralds justice, precise and inexorable as a clock\'s toll. All sins are cleansed in flame, dissipating like night beneath the dawn\'s gaze.\r\n\r\n', 47, 587, '10.80%', '48.60%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Darkness Breaker'),
(211, 'Woodland Aria', 'Pistols', 5, 'Crit Rate%', 'wp_woodland_aria.png', 'ATK is increased by [12, 3]%. Inflicting Aero Erosion on the target gives [24, 6]% Aero DMG Bonus for 10s. Hitting targets with Aero Erosion reduces their Aero RES by [10, 1.5]% for 20s. Effects of the same name cannot be stacked.', 'All things exist within the lines of poetry. Every sound has its meters and rhymes. The forest\'s melodies ascend in spirals toward the moon\'s silvered grace, harmonized by the nightingales\' chorus. When the final note falls and vanishes into the silent earth, a flawless chord echoes endlessly in the depths of this boundless realm.', 40, 500, '8.00%', '36.00%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Lingering Summer Tune'),
(212, 'Defier\'s Thorn', 'Sword', 5, 'HP%', 'wp_defier_s_thorn.png', 'Max HP is increased by [12, 3]%. 15s after casting Intro Skill or Basic Attacks, ignore [8, 2]% of the target\'s DEF when dealing damage. If the target has at least 1 stack of Aero Erosion, the DMG taken by the target is Amplified by [20, 5]%.', 'The surging tides force the crown of thorns upon the knight, out of which the knight forges this sword. Unburdened by the crown, the knight waded through the roaring waves unwaveringly.', 33, 412, '16.05%', '72.23%', 'Inert Metallic Drip', 'Reactive Metallic Drip\r\n', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'A Free Knight\'s Tarantella'),
(213, 'Wildfire Mark', 'Broadblade', 5, 'Crit DMG%', 'wp_wildfire_mark.png', 'Increases ATK by [12, 3]%. Performing Intro Skill or Resonance Liberation increases Resonance Liberation DMG by [24, 6]% for 6s. Dealing Heavy Attack DMG extends this effect by 4s, up to 1 time. Each successful extension gives [24, 6]% Fusion DMG Bonus to all Resonators in the team for 30s. Effects of the same name cannot be stacked.', 'The young wolf races through the wilds, shedding every shadow that once held her back. The lone wolf strides into the arena, cutting down each obstacle in her path. She seizes victory. She claims glory. She raises everything she has high above. She belongs to the arena, but even more, she belongs to herself.', 47, 587, '10.80%', '48.60%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Blazing Starfire'),
(214, 'Lethean Elegy', 'Rectifier', 5, 'Crit Rate%', 'wp_lethean_elegy.png', 'ATK is increased by [12, 3]%. Within 12s after dealing Echo Skill DMG, gain [32, 8]% Resonance Skill DMG Bonus and [32, 8]% Echo Skill DMG Amplification, and ignore [8, 2]% of the target\'s DEF when dealing damage.', 'I am not there. I do not die. I shall be death\'s companion—with euphoric delights I drown my fear, with the coming days I trade for the past.', 47, 587, '5.40%', '24.30%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Underworld Requiem'),
(215, 'Moongazer\'s Sigil', ' Gauntlets', 5, 'Crit Rate%', 'wp_moongazer_s_sigil.png', 'Increases ATK by [12, 3]%. Casting Intro Skill or Resonance Liberation increases Resonance Liberation DMG by [20, 5]% for 15s. Obtaining Shield allows Resonance Liberation DMG to ignore [7.2, 1.2]% of the target\'s DEF for 7s, stacking up to 5 times. This effect is triggered once every 0.5s. Upon casting Intro Skill, this effect reaches max stacks immediately, lasting for 3s.', 'By what means do all things endure? By light and heat, by matter and word, by the mechanics of converging chances, by the soft dissolution into silence, by a moment that mimics the eternal... All things rise and fall in endless rhythm, each bearing its meaning. As for hers, it lies here within her grasp.\r\n\r\n', 40, 500, '8.00%', '36.00%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Plenilune Radiance'),
(216, 'Thunderflare Dominion', 'Broadblade', 5, 'Crit Rate%', 'wp_thunderflare_dominion.png', 'Increases ATK by [12, 3]%. Casting Intro Skill or Resonance Skill increases Heavy Attack DMG by [20, 5]% for 15s. Obtaining Shield allows Heavy Attack DMG to ignore [7.2, 1.2]% of the target\'s DEF for 7s, stacking up to 5 times. This effect is triggered once every 0.5s', 'Thunder shall purge her pain and weakness. From the crucible of blood and sand, the Sun rises. Not dimmed by dust, but ablaze in her full radiance.', 54, 675, '2.70%', '12.15%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core\r\n', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Thunderblaze Eminence'),
(217, 'Lux & Umbra', 'Pistols', 5, 'Crit DMG%', 'wp_lux_umbra.png', 'ATK is increased by [12, 3]%. Upon dealing Echo Skill DMG, gain [24, 6]% Heavy Attack DMG Amplification for 6s. Upon dealing Heavy Attack DMG, gain [24, 6]% Echo Skill DMG Amplification for 6s. DMG Amplification on each attack is capped at [24, 6]%. While both effects are active, dealing damage ignores [8, 2]% of the target\'s DEF.', 'From darkness she seizes power, layering sins upon herself. To hunt. To kill. To deliver a relentless and fatal blow to all evil. From the light she falls, with her vows etched in her mind. For the deceased. For the living. For her pistols\' true targets.\r\n\r\n', 47, 587, '10.80%', '48.60%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston\r\n', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'To Fire She Returns'),
(218, 'Emerald Sentence', 'Sword', 5, 'Crit Rate%', 'wp_emerald_sentence.png', 'ATK is increased by [12, 3]%. Casting Echo Skill within 10s after casting Intro Skill or Basic Attack grants 1 stack of Bamboo Cleaver, which grants [30, 7.5]% Heavy Attack DMG Bonus to the wielder. This effect can be triggered by Echoes of the same name once only, stacking up to 2 times, lasting for 12s. Casting Echo Skill at max stacks does not reset the duration. This effect can be triggered once every 10s and ends early if the wielder is switched off the field. Casting Intro Skill grants [20, 5]% Echo Skill DMG Bonus to all Resonators in the team for 30s. Effects of the same name cannot be stacked.', 'Bamboo, hollow yet full; People, whole yet seldom true. Bamboo speaks without deceit, acts without conceit, seeks no vanity. Few ever measure up thus.', 47, 587, '5.40%', '24.30%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip\r\n', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'When A Heart Settles'),
(219, 'Kumokiri', 'Broadblade', 5, 'Crit Rate%', 'wp_kumokiri.png', 'ATK is increased by [12, 3]%. When the wielder casts Intro Skill or inflicts Negative Statuses, they gain [8, 2]% Resonance Liberation DMG Bonus, stacking up to 3 times for 15s. At max stacks, when Resonators in the team inflict Negative Statuses, they gain [24, 6]% All-Attribute DMG Bonus for 15s. Effects of the same name cannot be stacked.', 'A crimson thread emerges in the void, as if binding the structures of all things onto a single thread. At her fingertips, the endless season is drawn taut, snipped, and rewoven, until the scattered path at last converges once more upon this timeline.', 40, 500, '8.00%', '36.00%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core\r\n', 'Thread of Fate'),
(220, 'Spectrum Blaster', 'Pistols', 5, 'Crit Rate%', 'wp_spectrum_blaster.png', 'Increases ATK by [12, 3]%. Casting Intro Skill or dealing Basic Attack DMG to targets increases the wielder\'s Basic Attack DMG Bonus by [36, 9]% for 4s. Each time the wielder inflicts Tune Rupture - Shifting or Tune Strain - Shifting during Basic Attacks, all DMG dealt by Resonators in the team is increased by [8, 2]% for 30s, up to 3 stacks. Effects of the same name cannot be stacked.', 'Prismatic light dances at her fingertips, arcs of color carving radiant trails. Every rushing hue converges upon her aim, and at last, she reaches a sky where nothing lies beyond her sight.', 47, 587, '5.40%', '24.30%', 'Incomplete Combustor', 'Aftertune Combustor', 'Remnant Combustor', 'Reverb Combustor', 'Fractured Exoswarm Pendant', 'Worn Exoswarm Pendant', 'Chipped Exoswarm Pendant', 'Intact Exoswarm Pendant', 'Attendance Exemption Protocol'),
(221, 'Starfield Calibrator', 'Broadblade', 5, 'Energy Regen%', 'wp_starfield_calibrator.png', 'Increases DEF by [16, 4]%. Casting Resonance Skill restores [8, 2] points of Concerto Energy. This effect can be triggered 1 every 20s. When the wielder heals Resonators, increases Crit. DMG of all nearby Resonators in the team by [20, 5]% for 4s. Effects of the same name cannot be stacked.', 'Every pattern can be observed. Every phenomenon can be understood. The ideal may lie light-years away, yet the path toward it rests within her own hands.', 33, 412, '17.12%', '77.04%', 'LF Carved Crystal\r\n', 'MF Carved Crystal', 'HF Carved Crystal', 'FF Carved Crystal', 'Fractured Exoswarm Pendant', 'Worn Exoswarm Pendant', 'Chipped Exoswarm Pendant', 'Intact Exoswarm Pendant', 'Definite Solution'),
(222, 'Radiance Cleaver', 'Broadblade', 5, 'Crit DMG%', 'wp_radiance_cleaver.png', 'Increases ATK by [12, 3]%. Dealing damage to targets under Tune Strain - Interfered grants [24, 3]% Resonance Liberation Bonus for 3s. Retriggering the effect resets its duration.', 'Spacetrek Collective \"Synth Armament\" Series Model: SCSA-LHRi-BB325042 Forged from compound technology that fuses Exostrider biomorphic components with Tacetite, this weapon offers two core features: frequency auto-adaptation and user binding. Its power scales directly with the wielder\'s Forte, growing sharper through dedicated Forte training. The light patterns along the blade shift in response to the wielder\'s frequency fluctuations. It crystallizes reason into a concentrated force—a tool to cut through obstacles as well as a measure for charting the unknown. Ideal for the edge breakers who carve their path forward with unwavering resolve.', 47, 587, '10.80%', '48.60%', 'LF Carved Crystal', 'MF Carved Crystal', 'HF Carved Crystal\r\n', 'FF Carved Crystal', 'Fractured Exoswarm Pendant', 'Worn Exoswarm Pendant', 'Chipped Exoswarm Pendant', 'Intact Exoswarm Pendant', 'Edge Breaker'),
(223, 'Laser Shearer', 'Sword', 5, ' Energy Regen%', 'wp_laser_shearer.png', 'Increases ATK by [12, 3]%. Dealing damage to targets under Tune Strain - Interfered grants [24, 3]% Resonance Skill Bonus for 3s. Retriggering the effect resets its duration.', 'Spacetrek Collective \"Synth Armament\" Series Model: SCSA-LHRi-SWD201052 Forged from compound technology that fuses Exostrider biomorphic components with Tacetite, this weapon offers two core features: frequency auto-adaptation and user binding. Its power scales directly with the wielder\'s Forte, growing sharper through dedicated Forte training. The light patterns along the blade shift in response to the wielder\'s frequency fluctuations. Each strike expresses a refined intuition, a \"razor\" that cuts away unnecessary possibilities. Ideal for the signal catchers who discern the greater picture from the smallest details and make sound judgments.', 47, 587, '8.64%', '38.88%', 'Broken Wing Polarizer', 'Monowing Polarizer', 'Polywing Polarizer', 'Layered Wing Polarizer', 'LF Mech Core', 'MF Mech Core', 'HF Mech Core', 'FF Mech Core', 'Signal Catcher'),
(224, 'Phasic Homogenizer', 'Pistols', 5, 'Crit DMG%', 'wp_phasic_homogenizer.png', 'Increases ATK by [12, 3]%. After a Resonator in the team casts a Tune Break skill, it grants [20, 2.5]% All-Attribute DMG Bonus to the wielder for 14s.', 'Spacetrek Collective \"Synth Armament\" Series Model: SCSA-LHRi-PSTL325052 Forged from compound technology that fuses Exostrider biomorphic components with Tacetite, this weapon offers two core features: frequency auto-adaptation and user binding. Its power scales directly with the wielder\'s Forte, growing sharper through dedicated Forte training. Projectile and rifling are spectrally tuned to unleash a potent frequency disturbance on impact, exposing and shattering a target\'s weak points. It serves as both a benchmark of precision and a weapon that pierces with unwavering focus. Ideal for insight bearers who act with deliberate caution and perceive what others overlook.', 47, 587, '10.80%', '48.60%', 'Incomplete Combustor', 'Aftertune Combustor', 'Remnant Combustor', 'Reverb Combustor', 'Fractured Exoswarm Pendant', 'Worn Exoswarm Pendant', 'Chipped Exoswarm Pendant', 'Intact Exoswarm Pendant', 'Insight Bearer'),
(225, 'Pulsation Bracer', 'Gauntlets', 5, 'Crit Rate%', 'wp_pulsation_bracer.png', 'Increases ATK by [12, 3]%. Dealing damage to targets under Tune Strain - Interfered grants [6, 0.7]% Basic Attack DMG Bonus for 3s, stacking up to 4 times. This effect can be triggered 1 every 0.5s. Retriggering the effect resets its duration.', 'Spacetrek Collective \"Synth Armament\" Series Model: SCSA-LHRi-GNTL522152 Forged from compound technology that fuses Exostrider biomorphic components with Tacetite, this weapon offers two core features: frequency auto-adaptation and user binding. Its power scales directly with the wielder\'s Forte, growing sharper through dedicated Forte training. The armor\'s spectrum shifts as it restores kinetic energy. The Pulsation Bracer predicts the wearer\'s stance to amplify the stored reactive torque and release it in a single, instantaneous surge—a decisive force delivered at the critical moment. Ideal for the barrier breachers who advance with steady resolve and stand unshaken under pressure.\r\n\r\n', 47, 587, '5.40%', '24.30%', 'LF Waveworn Shard', 'MF Waveworn Shard', 'HF Waveworn Shard', 'FF Waveworn Shard', 'LF Mech Core', 'MF Mech Core', 'HF Mech Core', 'FF Mech Core', 'Barrier Breacher'),
(226, 'Boson Astrolabe', 'Rectifier', 5, 'Energy Regen%', 'wp_boson_astrolabe.png', 'Increases ATK by [12, 3]%. After a Resonator in the team casts a Tune Break skill, it grants a [12, 1.5]% ATK increase and [12, 1.5]% Basic Attack DMG Bonus to the wielder for 14s.', 'Spacetrek Collective \"Synth Armament\" Series Model: SCSA-LHRi-RCTF325062 Forged from compound technology that fuses Exostrider biomorphic components with Tacetite, this weapon offers two core features: frequency auto-adaptation and user binding. Its power scales directly with the wielder\'s Forte, growing sharper through dedicated Forte training. Composed of a spectral ring-lens and layered glass plates, the device captures even the faintest frequency shifts. Like a guiding star that leads the seekers through a sea of tangled thoughts, it maps possibilities before they take shape. Ideal for the path observers who perceive the world a step ahead.', 42, 525, '8.64%', '38.88%', 'Spliced String', 'Broken String', 'Solidified String', 'Melodic String', 'LF Exoswarm Core', 'MF Exoswarm Core', 'HF Exoswarm Core', 'FF Exoswarm Core', 'Path Observer\r\n'),
(227, 'Everbright Polestar', 'Sword', 5, 'Crit Rate%', 'wp_everbright_polestar.png', 'Increases All-Attribute DMG Bonus by [12, 3]%. When inflicting Tune Rupture - Shifting or Fusion Burst, the wielder\'s Resonance Liberation DMG ignores [32, 8]% DEF and [10, 5]% Fusion RES on targets for 8s.', 'As you drift across the hushed sea of stars, stardust scatters beside you as time crumbles in your wake. All that remains is the unyielding loneliness, warped, diluted, and remade into the plumes of your wings. The universe sends you on a tribulation of silence, yet you travel on, repaying in radiance.', 47, 587, '5.40%', '24.30%', 'Broken Wing Polarizer', 'Monowing Polarizer', 'Polywing Polarizer', 'Layered Wing Polarizer', 'LF Mech Core', 'MF Mech Core', 'HF Mech Core', 'FF Mech Core', 'Starchaser'),
(228, 'Daybreaker\'s Spine', 'Gauntlets', 5, 'Crit Rate%', 'wp_daybreaker_s_spine.png', 'Increases ATK by [12, 3]%. After dealing Basic Attack DMG, the wielder gains [20, 5]% Spectro DMG Bonus for 4s. Each time after the wielder inflicts Tune Strain - Shifting on the target, they gain [20, 5]% Basic Attack DMG Amplification and their Basic Attack DMG ignores [10, 2.5]% of the target\'s DEF for 6s.', 'Those are not ridges of the mountains, but the spine of the earth, carrying the night. They protrude from the abdomen of darkness. From the incision spills the light of new life. Your shadow was nailed to the dying night. With the breaking dawn, your flesh shall rise. Let it knock open every door of denial.', 47, 587, '5.40%', '24.30%', 'LF Waveworn Shard', 'MF Waveworn Shard', 'HF Waveworn Shard', 'FF Waveworn Shard', 'LF Mech Core', 'MF Mech Core', 'HF Mech Core', 'FF Mech Core', 'Suturing Dayline'),
(229, 'Solsworn Ciphers', 'Gauntlets', 5, 'Crit DMG%', 'wp_solsworn_ciphers.png', 'Increases ATK by [12, 3]%. Casting Intro Skill or Echo Skill grants [32, 8]% Echo Skill DMG Amplification for 15s. When dealing Echo Skill DMG, Aero DMG ignores [10, 2.5]% of the target\'s DEF for 6s.', 'Sunlight gathers. The answer is made plain. What must be done awaits. The Rein is in your hand. Step forward, toward the sunlit end.', 47, 587, '10.80%', '48.60%', 'LF Waveworn Shard', 'MF Waveworn Shard', 'HF Waveworn Shard', 'FF Waveworn Shard', 'LF Mech Core', 'MF Mech Core', 'HF Mech Core', 'FF Mech Core', 'Sunward'),
(231, 'Autumntrace', 'Broadblade', 4, 'Crit Rate%', 'wp_autumntrace.png', 'Increases ATK by [4, 2.2]% upon dealing Basic Attack DMG or Heavy Attack DMG, stacking up to 5 time(s). This effect lasts for 7s and can be triggered 1 time(s) every 1s.', 'This Broadblade is a ceremonial weapon used in Huanglong\'s Magistrate Inauguration Ceremonies. The golden ginkgo leaf pattern symbolizes Huanglong\'s resilience, thriving in a world that has left it behind.', 33, 412, '4.50', '20.25%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core\r\n', 'FF Whisperin Core\r\n', 'Edge Direction'),
(232, 'Lumingloss', 'Sword', 4, 'ATK%', 'wp_lumingloss.png', 'When Resonance Skill is cast, increases Basic Attack DMG Bonus and Heavy Attack DMG Bonus by [20, 11]%, stacking up to 1 time(s). This effect lasts for 10s and can be triggered 1 time(s) every 1s.', 'This Sword is a ceremonial weapon used in Huanglong\'s Magistrate Inauguration Ceremonies. The golden ginkgo leaf pattern symbolizes Huanglong\'s resilience, thriving in a world that has left it behind.', 31, 387, '8.10%', '36.45%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Pale Gale'),
(233, 'Thunderbolt', 'Pistols', 4, 'ATK%', 'wp_thunderbolt.png', 'When hitting a target with Basic Attacks or Heavy Attacks, increases Resonance Skill DMG Bonus by [7, 4]%, stacking up to 3 time(s). This effect lasts for 10s and can be triggered 1 time(s) every 1s.', 'These Pistols are ceremonial weapons used in Huanglong\'s Magistrate Inauguration Ceremonies. The golden ginkgo leaf pattern symbolizes Huanglong\'s resilience, thriving in a world that has left it behind.', 31, 387, '8.10%', '36.45%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Unstoppable'),
(234, 'Stonard', 'Gauntlets', 4, 'Crit Rate%', 'wp_stonard.png', 'Casting Resonance Skill increases the wielder\'s Resonance Liberation DMG Bonus by [18, 9]%, lasting for 15s.', 'These Gauntlets are ceremonial weapons used in Huanglong\'s Magistrate Inauguration Ceremonies. The golden ginkgo leaf pattern symbolizes Huanglong\'s resilience, thriving in a world that has left it behind.', 33, 412, '4.50%', '20.25%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Wallbreaker'),
(235, 'Augment', 'Rectifier', 4, 'Crit Rate%', 'wp_augment.png', 'Casting Resonance Liberation increases the wielder\'s ATK by [15, 8.25]%, lasting for 15s.', 'This Rectifier is a ceremonial weapon used in Huanglong\'s Magistrate Inauguration Ceremonies. The golden ginkgo leaf pattern symbolizes Huanglong\'s resilience, thriving in a world that has left it behind.', 33, 412, '4.50%', '20.25%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring\r\n', 'Tailored Ring', 'Forgiving Resilience'),
(236, 'Discord', 'Broadblade', 4, 'Energy Regen%', 'wp_discord.png', 'When Resonance Skill is cast, restores [8, 2] Concerto Energy. This effect can be triggered 1 time(s) every 20s.', 'A descending adagio. This broadblade dominates the battlefield with the power of discordance. The curtain never falls on a masterpiece.', 27, 337, '11.52%', '51.84%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Ceaseless Aria'),
(237, 'Overture', 'Sword', 4, 'Energy Regen%', 'wp_overture.png', 'When Resonance Skill is cast, restores [8, 2] Concerto Energy. This effect can be triggered 1 time(s) every 20s.', 'An ascending crescendo. This enchanting sword effortlessly cuts through anything in its way, like a glorious prelude.', 27, 337, '11.52%', '51.84%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Ceaseless Aria'),
(238, 'Cadenza', 'Pistols', 4, 'Energy Regen%', 'wp_cadenza.png', 'When Resonance Skill is cast, restores [8, 2] Concerto Energy. This effect can be triggered 1 times every 20s.', 'An ascending crescendo. These pistols unleash bullets with the force of thunder, tearing through the heavens like a symphony of destruction.', 27, 337, '11.52%', '51.84%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Ceaseless Aria'),
(239, 'Marcato', 'Gauntlets', 4, 'Energy Regen%', 'wp_marcato.png', 'When Resonance Skill is cast, restores [8, 2] Concerto Energy. This effect can be triggered 1 times every 20s.', 'A descending adagio. These gauntlets pulsate with the power of surging waves, shattering anything in their path like a deadly hymn.', 27, 337, '11.52%', '51.84%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Ceaseless Aria'),
(240, 'Variation', 'Rectifier', 4, 'Energy Regen%', 'wp_variation.png', 'When Resonance Skill is cast, restores [8, 2] Concerto Energy. This effect can be triggered 1 times every 20s.', 'A descending adagio. This rectifier opens up an insightful window into the situation, changing the tune of the intense battle concerto.', 27, 337, '11.52%', ' 51.84%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Ceaseless Aria'),
(241, 'Broadblade#41', 'Broadblade', 4, 'Energy Regen%', 'wp_broadblade_41.png', 'When the Resonator\'s HP is above 80%, increases ATK by [12, 3]%. When the Resonator\'s HP is below [40, 10]%, gives [5, 1.25]% healing when dealing Basic Attack DMG or Heavy Attack DMG. This effect can be triggered 1 time(s) every 8s.', 'An improved version of a mass-produced broadblade model developed in Huanglong. With its formidable performance and innovative technologies, this broadblade carries a weight only to be wielded by seasoned warriors.', 33, 412, '7.20%', '32.40%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core\r\n', 'MF Whisperin Core\r\n', 'HF Whisperin Core\r\n', 'FF Whisperin Core\r\n', 'Veteran'),
(242, 'Sword#18', 'Sword', 4, 'ATK', 'wp_sword_18.png', 'When the Resonator\'s HP drops below [40, 10]%, increases Heavy Attack DMG Bonus by [18, 4.5]% and gives [5, 1.25]% healing when dealing Heavy Attack DMG. This effect can be triggered 1 time(s) every 8s.', 'An improved version of a mass-produced sword model developed in Huanglong. With its sleek blade and minimalist design, this sword is exclusively crafted for the skilled hands of seasoned warriors.', 31, 387, '8.10%', '36.45%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Daybreak'),
(243, 'Pistols#26', 'Pistols', 4, 'ATK%', 'wp_pistols_26.png', 'When the Resonator takes no damage, increases ATK by [6, 1.5]% every 5s, stacking up to 2 time(s). This effect lasts for 8s. When the Resonator takes damage, loses 1 stacks and heals [5, 1.25]% of their Max HP.', 'The Huaxu Academy has developed practical, high-performance pistols based on previous source energy weapons, showcasing their meticulous research and aiming for excellence.', 31, 387, '8.10%', '36.45%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Omniscient'),
(244, 'Gauntlets#21D', 'Gauntlets', 4, 'Energy Regen%', 'wp_gauntlets_21d.png', 'When the Resonator dashes or dodges, increases ATK by [8, 2]%. Increases Dodge Counter DMG by [50, 12.5]%, lasting for 8s. When Dodge Counter is performed, heals [5, 1.25]% of the Resonator\'s Max HP. This effect can be triggered 1 time(s) every 6s.', 'Huaxu Academy has independently improved and developed the first set of highly practical high-performance Gauntlets based on the previous source energy weapons, representing the care and warmth of the Academy, stable and lasting.', 31, 387, '8.64%', '38.88%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Mastermind'),
(245, 'Rectifier#25', 'Rectifier', 4, 'Energy Regen%', 'wp_rectifier_25.png', 'When Resonance Skill is cast, if the Resonator\'s HP is below 60%, heals [5, 1.25]% of their Max HP. This effect can be triggered 1 time(s) every 8s. If the Resonator\'s HP is above 60%, increases ATK by [12, 3]%, lasting for 10s.', 'An improved version of a Rectifier prototype from Huanglong\'s next-gen weaponry project. This device is characterized by its powerful, purified output and sound that resonates with the decisively strong-willed.', 27, 337, '11.52%', '51.84%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Dawnbringer'),
(246, 'Dauntless Evernight', 'Broadblade', 4, 'DEF%', 'wp_dauntless_evernight.png', 'When Intro Skill is cast, increases ATK by [8, 2]% and DEF by [15, 3.75]%, lasting for 15s.', 'A weapon designed to commemorate the Midnight Rangers\' preparedness. \"Autumn fades in endless nights, ready blades gleam with silent might.\"', 27, 337, '13.68%', '61.56%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Battlebound'),
(247, 'Commando of Conviction', 'Sword', 4, 'ATK%', 'wp_commando_of_conviction.png', 'When Intro Skill is cast, increases ATK by [15, 3.75]%, lasting for 15s.', 'A weapon designed to commemorate the Midnight Rangers\' courage. \"A thousand echoes carry the war\'s tale, as spirits unite in resounding gorges of valor.”', 33, 412, '6.75%', '30.38%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Unyielding'),
(248, 'Undying Flame', 'Pistols', 4, 'ATK%', 'wp_undying_flame.png', 'When Intro Skill is cast, increases Resonance Skill DMG Bonus by [20, 5]% for 15s.', 'A weapon designed to commemorate the Midnight Rangers\' dedication. \"Let my body ablaze, flames dance to banish all evil\'s haze.\"', 33, 412, '6.75%', '30.38%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Loyalty'),
(249, 'Amity Accord', 'Gauntlets', 4, 'DEF%', 'wp_amity_accord.png', 'When Intro Skill is cast, increases Resonance Liberation DMG Bonus by [20, 5]%, lasting for 15s.', 'A weapon designed to commemorate the Midnight Rangers\' comradeship. \"Thin garments yield to icy moons, while armor withstands the chill of stars.\"', 27, 337, '13.68%', '61.56%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Camaraderie'),
(250, 'Jinzhou Keeper', 'Rectifier', 4, 'ATK%', 'wp_jinzhou_keeper.png', 'Casting Intro Skill increases the wielder\'s ATK by [8, 2]% and HP by [10, 2.5]%, lasting for 15s.', 'A weapon designed to commemorate the Midnight Rangers\' vigilant protection of Jinzhou. \"Cast your gaze towards the north, where the city\'s silhouette fades, its gates veiled by the tranquil rain.\"\r\n\r\nContact us\r\nPrivacy Policy\r\nMarvel Rivals Tracker\r\nZZZ Characters\r\nCrimson Desert Database\r\nSub', 31, 387, '8.10%', '36.45%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Guardian'),
(251, 'Helios Cleaver', 'Broadblade', 4, 'ATK%', 'wp_helios_cleaver.png', 'Within 12s after Resonance Skill is cast, increases ATK by [3, 0.75]% every 2s, stacking up to 4 time(s). This effect can be triggered 1 time(s) every 12s. When the number of stacks reaches 4, all stacks will be reset within 6s.', 'The Broadblade born from the aerial phenomenon. The blacksmith incorporates the feelings of witnessing the alien star into the weapon, making it look hollow and light, but it can exert the invincible gravity of the starfall.', 33, 412, '6.75%', '30.38%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Plasma Recoiler'),
(252, 'Lunar Cutter', 'Sword', 4, 'ATK%', 'wp_lunar_cutter.png', 'Equipped Resonator gains 6 stack(s) of Oath upon entering the battlefield. Each stack increases ATK by [2, 0.5]%, up to 6 stacks. This effect can be triggered 1 time(s) every 12s. The equipped Resonator loses 1 stack(s) of Oath every 2s, and gains 6 stack(s) upon defeating an enemy.', 'The Sword born from the aerial phenomenon. The forger integrates the feelings of witnessing the alien star into the weapon, making it look light and sharp, but it can exert the energy of breaking the sky and cutting iron like mud.', 33, 412, '6.75%', '30.38%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Preordained'),
(253, 'Novaburst', 'Pistols', 4, 'ATK%', 'wp_novaburst.png', 'When the Resonator dashes or dodges, increases ATK by [4, 1]%, stacking up to 3 time(s). This effect lasts for 8s.', 'Pistols born from the strange phenomena in the sky. The forger infused the weapon with the feelings from witnessing the strange star, making it look hollow and light, yet extremely stable, with the power of thunder when it fires.', 33, 412, '6.75%', '30.38%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston\r\n', 'Flawless Phlogiston\r\n', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Ever-changing'),
(254, 'Hollow Mirage', 'Gauntlets', 4, 'ATK%', 'wp_hollow_mirage.png', 'When Resonance Liberation is cast, grants 3 stack(s) of Iron Armor. Each stack increases ATK and DEF by [3, 0.50]%, stacking up to 3 time(s). When the Resonator takes damage, reduces the number of stacks by 1.', 'The Gauntlets born from the strange phenomenon in the sky. The blacksmith infused the feelings of witnessing the strange star into the weapon, making it look hollow and light, but it can exert a tremendous momentum while protecting the user.', 33, 412, '6.75%', '30.38%', 'Cadence Seed\r\n\r\n', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Celestial Blessing'),
(255, 'Comet Flare', 'Rectifier', 4, 'HP%', 'wp_comet_flare.png', 'When dealing Basic Attack DMG or Heavy Attack DMG, increases Healing Bonus by [3, 0.75]%, stacking up to 3 time(s). This effect lasts for 8s and can be triggered 1 time(s) every 0.6s.', 'A Rectifier born born from an aerial phenomenon. Capturing the essence of an alien star, its design is delicate and lightweight, yet it remains sturdy and adaptable.', 33, 412, '6.75%', '30.38%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ringz', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Luminous Protection'),
(256, 'Waning Redshift', 'Broadblade', 4, 'ATK%', 'wp_waning_redshift.png', 'Casting the Resonance Skill grants [6, 1] Resonance Energy and increases ATK by [10, 2.5]%, lasting for 16s. This effect can be triggered once every 20s.', 'A prototype weapon designed by the Black Shores for elite combatants. This broadblade takes its name from the fate of a blazar—a galactic nucleus whose blinding radiance pierces the cosmos, shining unmistakably across billions of light years.', 37, 462, '4.05%', '18.23%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Intergalactic Gaze'),
(257, 'Endless Collapse', 'Sword', 4, 'ATK%', 'wp_endless_collapse.png', 'Casting the Resonance Skill grants [6, 1] Resonance Energy and increases ATK by [10, 2.5]%, lasting for 16s. This effect can be triggered once every 20s.', 'A prototype weapon designed by the Black Shores for elite combatants. This sword takes its name from the heart of a blazar—a galactic nucleus whose blinding radiance pierces the cosmos, shining unmistakably across billions of light years.', 37, 462, '4.05%', '18.23%', 'Inert Metallic Drip', 'Reactive Metallic Drip\r\n', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Intergalactic Gaze');
INSERT INTO `weapons` (`id`, `name`, `type`, `rarity`, `main_stat`, `image_url`, `description`, `story`, `atk_base`, `atk_max`, `stat_base`, `stat_max`, `mat_1_t1`, `mat_1_t2`, `mat_1_t3`, `mat_1_t4`, `mat_2_t1`, `mat_2_t2`, `mat_2_t3`, `mat_2_t4`, `skill_name`) VALUES
(258, 'Relativistic Jet', 'Pistols', 4, 'ATK%', 'wp_relativistic_jet.png', 'Casting the Resonance Skill grants [6, 1] Resonance Energy and increases ATK by [10, 2.5]%, lasting for 16s. This effect can be triggered once every 20s.', 'A prototype weapon designed by the Black Shores for elite combatants. These pistols take their name from the incessant course of destruction of a blazar—a galactic nucleus whose blinding radiance pierces the cosmos, shining unmistakably across billions of light years.', 37, 462, '4.05%', '18.23%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston\r\n', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Intergalactic Gaze'),
(259, 'Celestial Spiral', 'Gauntlets', 4, 'ATK%', 'wp_celestial_spiral.png', 'Casting the Resonance Skill grants [6, 1] Resonance Energy and increases ATK by [10, 2.5]%, lasting for 16s. This effect can be triggered once every 20s.', 'A prototype weapon designed by the Black Shores for elite combatants. These gauntlets take their name from the tragic demise of a blazar—a galactic nucleus whose blinding radiance pierces the cosmos, shining unmistakably across billions of light years.', 37, 462, '4.05%', '18.23%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Intergalactic Gaze'),
(260, 'Fusion Accretion', 'Rectifier', 4, 'ATK%', 'wp_fusion_accretion.png', 'Casting the Resonance Skill grants [6, 1] Resonance Energy and increases ATK by [10, 2.5]%, lasting for 16s. This effect can be triggered once every 20s.', 'A prototype weapon designed by the Black Shores for elite combatants. This rectifier takes its name from the devastating might of a blazar—a galactic nucleus whose blinding radiance pierces the cosmos, shining unmistakably across billions of light years.', 37, 462, '4.05%', '18.23%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Intergalactic Gaze'),
(261, 'Somnoire Anchor', 'Sword', 4, 'ATK%', 'wp_somnoire_anchor.png', 'Gain 1 stack of Hiss when dealing damage to the target, with 1 stack generated every 1s. Hiss: each stack increases the wielder\'s ATK by [2, 0.5]% for 3s, stacking up to 10 times. Switching off the wielder clears all stacks. Gaining 10 stacks increases the wielder\'s Crit. Rate by [6, 1.5]%.', 'An anchor once used by Ivory Gatekeeper to stablize the Somnoire. However, it now looks different ever since Ivory Gatekeeper transformed into a white cat...', 37, 462, '4.05%', '18.23%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Meow!'),
(262, 'Call of the Abyss', 'Rectifier', 4, ' Energy Regen%', 'wp_call_of_the_abyss.png', 'Casting Resonance Liberation increases the Resonator\'s Healing Bonus by [16, 4]% for 15s.', 'Held by the keepers of this land, this scepter was once a symbol of dominion over its people and the architectural marvels they achieved. However, it has long lost its luster, and its grandeur blends into the ripples of the pipe organ melodies of Rinascita.', 27, 338, '11.52%', '51.84%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Pole of the Celestial Dome'),
(263, 'Meditations on Mercy', 'Broadblade', 4, 'ATK%', 'wp_meditations_on_mercy.png', 'Dealing DMG to enemies with Negative Statuses increases the wielder\'s ATK by [4, 1]% for 10s. This effect can be triggered 1 time per second, stackable up to 4 times.', 'This weapon draws its design inspiration from the play—Meditations on Mercy. In the brief pauses between each swing, a warrior wrestles with an inner conflict: to bring down righteous punishment or extend a hand of redemption? Behind every clash of steel is the struggle between wrath and mercy.', 37, 462, '4.05%', '18.23%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Rhetoric'),
(264, 'Fables of Wisdom', 'Sword', 4, 'ATK%', 'wp_fables_of_wisdom.png', 'Dealing DMG to enemies with Negative Statuses increases the wielder\'s ATK by [4, 1]% for 10s. This effect can be triggered 1 time per second, stackable up to 4 times.', 'This weapon draws its design inspiration from the play—Fables of Wisdom. A wayfarer once carried this sword, who spun fables of wisdom, passing on insights in the form of witty jests. Keen ears listened to the stories for the truth, while shallow minds heard only amusing punchlines.', 37, 462, '4.05%', '18.23%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Rhetoric'),
(265, 'Romance in Farewell', ' Pistols', 4, 'ATK%', 'wp_romance_in_farewell.png', 'Dealing DMG to enemies with Negative Statuses increases the wielder\'s ATK by [4, 1]% for 10s. This effect can be triggered 1 time per second, stackable up to 4 times.', 'This weapon draws its design inspiration from the play—Romance in Farewell. This pistol was once the symbol of the aspiration for repute, the weight of unrequited love, and the tremors of unspoken words. When the trigger is pulled, and the curtain drops, it turns into a long farewell and a sign of lingering sorrow in the heart of the bereaved.', 37, 462, '4.05%', '18.23%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Rhetoric'),
(266, 'Legend of Drunken Hero', 'Gauntlets', 4, 'ATK%', 'wp_legend_of_drunken_hero.png', 'Dealing DMG to enemies with Negative Statuses increases the wielder\'s ATK by [4, 1]% for 10s. This effect can be triggered 1 time per second, stackable up to 4 times.', 'This weapon draws its design inspiration from the play—Legend of Drunken Hero. From the cup flows a liquid that grants courage and strength, empowering the hero to defy fate and turn the tide with his gauntlets. Yet in this intoxicating delight lies peril—dulled senses become the hero\'s undoing as enemies close in. Thus, in those wine-stained pages, one always read about triumphs followed by defeats.', 37, 462, '4.05%', '18.23%', 'Cadence Seed', 'Cadence Bud\r\n', 'Cadence Leaf\r\n', 'Cadence Blossom\r\n', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Rhetoric'),
(267, 'Waltz in Masquerade', ' Rectifier', 4, 'ATK%', 'wp_waltz_in_masquerade.png', 'Dealing DMG to enemies with Negative Statuses increases the wielder\'s ATK by [4, 1]% for 10s. This effect can be triggered 1 time per second, stackable up to 4 times.', 'This weapon draws its design inspiration from the play—Waltz in Masquerade. A waltz is a dance of spectacle and masquerade, where the grand symphony drowns whispered secrets and swirling dresses conceal the exchange of letters and promises. The dancers speak a silent language, as smooth and precise as the perfect resonance of a rectifier.', 37, 462, '4.05%', '18.23%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Rhetoric'),
(268, 'Ocean\'s Gift', 'Rectifier', 4, 'ATK%', 'wp_ocean_s_gift.png', 'Dealing DMG to enemies with Spectro Frazzle increases the wielder\'s Spectro DMG by [6, 1]%, gaining 1 stack per second for 6s, stacking up to 4 times.', 'To fishers, the sea is their field of harvest. Harvest means hope.', 37, 462, '4.05%', '18.23%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Fish Catch\r\n'),
(269, 'Aureate Zenith', 'Broadblade', 4, 'Crit DMG%', 'wp_aureate_zenith.png', 'Casting Resonance Liberation increases ATK by [7.2, 3.9]% and grants [10.8, 5.9]% Heavy Attack DMG Bonus for 15s.', 'A Broadblade awarded to Gladiators of exceptional merit. Its engravings draw inspiration from Griffrexes—natural-born hunters and the first allies Septimontians found in this land. Their bond needs no words, radiant and pure, like the blazing sun that watches over all.', 33, 412, '9.00%', '40.50%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Oath of Tide Hunters'),
(270, 'Feather Edge', ' Sword', 4, ' Crit Rate%', 'wp_feather_edge.png', 'Casting Resonance Liberation increases ATK by [7.2, 3.9]% and grants [10.8, 5.9]% Resonance Liberation DMG Bonus for 15s.', 'A Sword awarded to Gladiators of exceptional merit. Its engravings draw inspiration from Griffrexes—natural-born hunters and the first allies Septimontians found in this land. Their bond needs no words, radiant and pure, like the blazing sun that watches over all.', 33, 412, '4.50%', '20.25%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Oath of Tide Hunters'),
(271, 'Solar Flame', ' Pistols', 4, 'Crit Rate%', 'wp_solar_flame.png', 'Dealing Basic Attack or Heavy Attack DMG increases ATK by [2.2, 1.2]% and grants [2.2, 1.2]% Heavy Attack DMG Bonus for 7s, stacking up to 4 times. This effect can be triggered 1 every 1s.', 'A pair of Pistols awarded to Gladiators of exceptional merit. Its engravings draw inspiration from Griffrexes—natural-born hunters and the first allies Septimontians found in this land. Their bond needs no words, radiant and pure, like the blazing sun that watches over all.', 33, 412, '4.50%', '20.25%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Oath of Tide Hunters'),
(272, 'Aether Strike', 'Sword', 4, 'Crit. DMG%', 'wp_aether_strike.png', 'Casting Resonance Liberation increases ATK by [7.2, 3.9]% and grants [10.8, 5.9]% Resonance Liberation DMG Bonus for 15s.', 'A pair of Gauntlets awarded to Gladiators of exceptional merit. Its engravings draw inspiration from Griffrexes—natural-born hunters and the first allies Septimontians found in this land. Their bond needs no words, radiant and pure, like the blazing sun that watches over all.\r\n', 33, 412, '9.00%', '40.50%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Oath of Tide Hunters'),
(273, 'Radiant Dawn', 'Rectifier', 4, 'Crit DMG%', 'wp_radiant_dawn.png', 'Casting Resonance Skill increases ATK by [9, 4.9]% and grants [9, 4.9]% Basic Attack DMG Bonus for 10s.', 'A Rectifier awarded to Gladiators of exceptional merit. Its engravings draw inspiration from Griffrexes—natural-born hunters and the first allies Septimontians found in this land. Their bond needs no words, radiant and pure, like the blazing sun that watches over all.', 33, 412, '9.00%', '40.50%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring\r\n', 'Tailored Ring', 'Oath of Tide Hunters'),
(274, 'Broadblade of Night', 'Broadblade', 3, 'ATK%', 'wp_broadblade_of_night.png', 'When Intro Skill is cast, increases ATK by [8, 2]%, lasting for 10s.', 'May victory prevail the lasting night. In addition to the sworn oath of protection, this broadblade also carries the resolution of those fighting souls.', 26, 325, '5.40%', '24.30%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Valiance'),
(275, 'Sword of Night', 'Sword', 3, 'ATK%', 'wp_sword_of_night.png', 'When Intro Skill is cast, increases ATK by [8, 2]%, lasting for 10s.', 'May victory prevail the lasting night. In addition to the sworn oath of protection, this sword also represents the ambition of those brave souls.', 26, 325, '5.40%', '24.30%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Valiance'),
(276, 'Pistols of Night', 'Pistols', 3, 'ATK%', 'wp_pistols_of_night.png', 'When Intro Skill is cast, increases ATK by [8, 2]%, lasting for 10s.', 'May victory prevail the lasting night. This type of pistol not only carries the oath of protection, but also the hope of rejuvenation.', 26, 325, '5.40%', '24.30%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Valiance'),
(277, 'Gauntlets of Night', 'Gauntlets', 3, 'ATK%', 'wp_gauntlets_of_night.png', 'When Intro Skill is cast, increases ATK by [8, 2]%, lasting for 10s.', 'May victory prevail the lasting night. In addition to the sworn oath of protection, these gauntlets also commemorate the sacrifices of those brave souls.', 26, 325, '5.40%', '24.30%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Valiance'),
(278, 'Rectifier of Night', 'Rectifier', 3, 'ATK%', 'wp_rectifier_of_night.png', 'When Intro Skill is cast, increases ATK by [8, 2]%, lasting for 10s.', 'May victory prevail the lasting night. In addition to the sworn oath of protection, this rectifier signifies the confidence of those fighting souls.', 26, 325, '5.40%', '24.30%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Pzresto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Valiance\r\n'),
(279, 'Originite: Type I', 'Broadblade', 3, ' DEF%', 'wp_originite_type_i.png', 'When Resonance Skill is cast, heals [3, 0.75]% of the Resonator\'s Max HP. This effect can be triggered 1 time(s) every 12s.', 'To create new Tacetite weapons, the Huaxu Academy designed this test Broadblade for technical verification. Its main feature is healing through attacks, improving the physical abilities of Resonators while exhibiting impressive weapon performance.', 24, 300, '8.55%', '38.48%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Temperance'),
(280, 'Originite: Type II', 'Sword', 3, 'ATK%', 'wp_originite_type_ii.png', 'When Resonance Liberation is cast, heals [5, 1.25]% of the Resonator\'s Max HP. This effect can be triggered 1 time(s) every 20s.', 'To create new Tacetite weapons, the Huaxu Academy designed this test Sword for technical verification. Its main feature is healing through attacks, improving the physical abilities of Resonators while exhibiting impressive weapon performance.', 26, 325, '5.40%', '24.30%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Vanquish'),
(281, 'Originite: Type III', 'Pistols', 3, 'ATK%', 'wp_originite_type_iii.png', 'When Dodge Counter is cast, heals [1.6, 0.4]% of the Resonator\'s Max HP. This effect can be triggered 1 time(s) every 6s.', 'To create new Tacetite weapons, the Huaxu Academy designed these test Pistols for technical verification. Their main feature is healing through attacks, improving the physical abilities of Resonators while exhibiting impressive weapon performance.', 26, 325, '5.40%', '24.30%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Alarcrity'),
(282, 'Originite: Type IV', 'Gauntlets', 3, 'Crit DMG%', 'wp_originite_type_iv.png', 'When dealing Basic Attack DMG, heals [0.5, 0.15]% of the Resonator\'s Max HP. This effect can be triggered 1 time(s) every 3s.', 'To create new Tacetite weapons, the Huaxu Academy designed these test Gauntlets for technical verification. Their main feature is healing through attacks, improving the physical abilities of Resonators while exhibiting impressive weapon performance.', 24, 300, ' 9.00%', '40.50%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Rejuvinate'),
